#include <bits/stdc++.h>
using namespace std;

int findLIS(vector<int>& nums, int n) {
    vector<int> dp;

    for(int num : nums) {
        auto it = lower_bound(dp.begin(), dp.end(), num);
        if(it == dp.end()) {
            dp.push_back(num);
        } else {
            *it = num;
        }
    }

    return dp.size();
}

int main() {
    int t;
    cin >> t;

    while(t--) {
        int n;
        cin >> n;

        vector<int> nums(n);
        for(int i = 0; i < n; i++) {
            cin >> nums[i];
        }

        cout << findLIS(nums, n) << endl;
    }

    return 0;
}

